 79→suspend fun FragmentActivity.handleUiPostRequest(methodName: String, bytes: ByteArray): ByteArray? {
 80→    return when (methodName) {
 81→        "searchInBrowser" -> searchInBrowser(bytes)
 82→        "updateDeckConfigs" -> updateDeckConfigsRaw(bytes)
 83→        "addImageOcclusionNote" -> {
 84→            val data = withCol { addImageOcclusionNoteRaw(bytes) }
 85→            undoableOp { OpChanges.parseFrom(data) }
 86→            launchCatchingTask {
 87→                // Allow time for toast message to appear before closing editor
 88→                delay(1000)
 89→                setResult(Activity.RESULT_OK)
 90→                finish()
 91→            }
 92→            data
 93→        }
 94→        "updateImageOcclusionNote" -> {
 95→            val data = withCol {
 96→                updateImageOcclusionNoteRaw(bytes)
 97→            }
 98→            undoableOp { OpChanges.parseFrom(data) }
 99→            launchCatchingTask {
100→                // Allow time for toast message to appear before closing editor
101→                delay(1000)
102→                setResult(NoteEditor.RESULT_UPDATED_IO_NOTE)
103→                finish()
104→            }
105→            data
106→        }
107→        else -> null
108→    }
109→}
