 24→fun AnkiActivity.exportApkgPackage(
 25→    exportPath: String,
 26→    withScheduling: Boolean,
 27→    withMedia: Boolean,
 28→    limit: ExportLimit
 29→) {
 30→    launchCatchingTask {
 31→        val onProgress: ProgressContext.() -> Unit = {
 32→            if (progress.hasExporting()) {
 33→                text = getString(R.string.export_preparation_in_progress)
 34→            }
 35→        }
 36→        withProgress(extractProgress = onProgress) {
 37→            withCol { exportAnkiPackage(exportPath, withScheduling, withMedia, limit) }
 38→        }
 39→        val factory =
 40→            (this@exportApkgPackage as ExportDialogsFactoryProvider).exportDialogsFactory()
 41→        val dialog = factory.newExportReadyDialog().withArguments(exportPath)
 42→        showAsyncDialogFragment(dialog)
 43→    }
 44→}
